from zeep import Client, Settings
from zeep.transports import Transport
from requests import Session
from requests.auth import HTTPBasicAuth
import getpass

def create_soap_client(wsdl_url, username, password):
    session = Session()
    session.auth = HTTPBasicAuth(username, password)
    transport = Transport(session=session)
    settings = Settings(strict=False, xml_huge_tree=True)
    client = Client(wsdl=wsdl_url, transport=transport, settings=settings)
    return client

def lookup_policy(client, policy_number, customer_name):
    try:
        response = client.service.PolicyLookup(
            PolicyNumber=policy_number,
            CustomerName=customer_name
        )
        return response
    except Exception as e:
        print(f"An error occurred: {e}")
        return None

def main():
    wsdl_url = "https://example.com/insurance?wsdl"
    username = input("Enter your username: ")
    password = getpass.getpass("Enter your password: ")

    client = create_soap_client(wsdl_url, username, password)

    policy_number = input("Enter policy number: ")
    customer_name = input("Enter customer name: ")

    response = lookup_policy(client, policy_number, customer_name)
    if response:
        print("Policy Details:", response)
    else:
        print("Failed to retrieve policy details.")

if __name__ == "__main__":
    main()